/*
 * Process Swapping Simulation in C
 * Demonstrates swap-in, swap-out operations and memory management
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_PROCESSES 10
#define RAM_SIZE_MB 512
#define DISK_TRANSFER_RATE 50 /* MB per second */

/* Process States */
typedef enum {
 NEW,
 READY,
 RUNNING,
 BLOCKED,
 SWAPPED_OUT
} ProcessState;

/* Process Control Block */
typedef struct {
 int pid;
 char name[20];
 int size_mb;
 ProcessState state;
 int memory_location; /* RAM address if in memory */
 int disk_location; /* Swap space address if swapped */
} PCB;

/* Memory Block */
typedef struct {
 int start_address;
 int size;
 bool is_free;
 PCB *process;
} MemoryBlock;

/* Swap Space */
typedef struct {
 int total_size;
 int used_size;
 PCB *swapped_processes[MAX_PROCESSES];
 int swapped_count;
} SwapSpace;

/* System Structure */
typedef struct {
 MemoryBlock memory;
 SwapSpace swap_space;
 PCB *ready_queue[MAX_PROCESSES];
 int ready_count;
 double total_swap_time;
} OS;

/* Function Prototypes */
void init_os(OS *os);
bool allocate_memory(OS *os, PCB *process);
void free_memory(OS *os, PCB *process);
bool swap_out(OS *os, PCB *process);
bool swap_in(OS *os, PCB *process);
void select_victim(OS *os, PCB **victim);
void calculate_swap_time(int size_mb);
void display_memory_status(OS *os);
void display_process(PCB *p);

/* Initialize OS */
void init_os(OS *os) {
 os->memory.start_address = 0;
 os->memory.size = RAM_SIZE_MB;
 os->memory.is_free = true;
 os->memory.process = NULL;

 os->swap_space.total_size = 1000; /* 1000MB swap space */
 os->swap_space.used_size = 0;
 os->swap_space.swapped_count = 0;

 os->ready_count = 0;
 os->total_swap_time = 0.0;

 printf("OS Initialized with %dMB RAM\n", RAM_SIZE_MB);
}

/* Allocate memory to a process */
bool allocate_memory(OS *os, PCB *process) {
 if (!os->memory.is_free || os->memory.size < process->size_mb) {
 return false; /* No free memory */
 }

 os->memory.process = process;
 os->memory.is_free = false;
 process->memory_location = os->memory.start_address;
 process->state = READY;

 return true;
}

/* Free memory block */
void free_memory(OS *os, PCB *process) {
 if (os->memory.process == process) {
 os->memory.is_free = true;
 os->memory.process = NULL;
 process->memory_location = -1;
 }
}

/* Swap out a process from RAM to disk */
bool swap_out(OS *os, PCB *process) {
 if (process->state == SWAPPED_OUT) {
 printf("Process %s is already swapped out\n", process->name);
 return false;
 }

 /* Calculate swap time */
 double transfer_time = (double)process->size_mb / DISK_TRANSFER_RATE;
 double total_time = transfer_time + 0.015; /* +15ms for seek + latency */
 os->total_swap_time += total_time;

 /* Write to swap space */
 if (os->swap_space.swapped_count >= MAX_PROCESSES) {
 printf("Swap space is full\n");
 return false;
 }

 process->disk_location = os->swap_space.used_size;
 os->swap_space.swapped_processes[os->swap_space.swapped_count] = process;
 os->swap_space.swapped_count++;
 os->swap_space.used_size += process->size_mb;

 /* Free memory */
 free_memory(os, process);

 /* Update process state */
 process->state = SWAPPED_OUT;

 /* Remove from ready queue */
 for (int i = 0; i < os->ready_count; i++) {
 if (os->ready_queue[i] == process) {
 for (int j = i; j < os->ready_count - 1; j++) {
 os->ready_queue[j] = os->ready_queue[j + 1];
 }
 os->ready_count--;
 break;
 }
 }

 printf("SWAP OUT: %s (%dMB) - Time: %.3fs\n", 
 process->name, process->size_mb, total_time);

 return true;
}

/* Swap in a process from disk to RAM */
bool swap_in(OS *os, PCB *process) {
 if (process->state != SWAPPED_OUT) {
 printf("Process %s is not swapped out\n", process->name);
 return false;
 }

 /* Check if memory is available */
 if (!os->memory.is_free) {
 printf("Memory not free, selecting victim process...\n");
 PCB *victim = NULL;
 select_victim(os, &victim);

 if (victim != NULL) {
 swap_out(os, victim);
 } else {
 printf("No process available to swap out\n");
 return false;
 }
 }

 /* Now memory should be free */
 if (os->memory.is_free && os->memory.size >= process->size_mb) {
 /* Calculate swap time */
 double transfer_time = (double)process->size_mb / DISK_TRANSFER_RATE;
 double total_time = transfer_time + 0.015;
 os->total_swap_time += total_time;

 /* Remove from swap space */
 for (int i = 0; i < os->swap_space.swapped_count; i++) {
 if (os->swap_space.swapped_processes[i] == process) {
 for (int j = i; j < os->swap_space.swapped_count - 1; j++) {
 os->swap_space.swapped_processes[j] = 
 os->swap_space.swapped_processes[j + 1];
 }
 os->swap_space.swapped_count--;
 break;
 }
 }
 os->swap_space.used_size -= process->size_mb;

 /* Allocate memory */
 allocate_memory(os, process);

 /* Add to ready queue */
 os->ready_queue[os->ready_count] = process;
 os->ready_count++;

 printf("SWAP IN: %s (%dMB) - Time: %.3fs\n", 
 process->name, process->size_mb, total_time);

 return true;
 }

 printf("Cannot swap in %s: insufficient memory\n", process->name);
 return false;
}

/* Select victim process using FIFO */
void select_victim(OS *os, PCB **victim) {
 if (os->ready_count > 0) {
 *victim = os->ready_queue[0]; /* First process in ready queue */
 printf("Victim selected: %s (FIFO)\n", (*victim)->name);
 } else {
 *victim = NULL;
 }
}

/* Calculate theoretical swap time */
void calculate_swap_time(int size_mb) {
 double transfer_time = (double)size_mb / DISK_TRANSFER_RATE;
 double seek_time = 0.010; /* 10ms */
 double latency = 0.005; /* 5ms */
 double total_time = transfer_time + seek_time + latency;

 printf("\n=== Swap Time Calculation ===\n");
 printf("Process Size: %dMB\n", size_mb);
 printf("Transfer Time: %.3fs (at %dMB/s)\n", transfer_time, DISK_TRANSFER_RATE);
 printf("Seek Time: %.3fs\n", seek_time);
 printf("Rotational Latency: %.3fs\n", latency);
 printf("TOTAL SWAP TIME: %.3fs\n", total_time);
}

/* Display memory status */
void display_memory_status(OS *os) {
 printf("\n=== Memory Status ===\n");
 printf("RAM: %dMB total, ", os->memory.size);
 printf("%s (%dMB free)\n", 
 os->memory.is_free ? "FREE" : "OCCUPIED",
 os->memory.is_free ? os->memory.size : 0);

 if (os->memory.process != NULL) {
 printf(" Running: %s (%dMB)\n", 
 os->memory.process->name, os->memory.process->size_mb);
 }

 printf("Swap Space: %dMB used\n", os->swap_space.used_size);
 printf("Swapped Processes: ");
 for (int i = 0; i < os->swap_space.swapped_count; i++) {
 printf("%s ", os->swap_space.swapped_processes[i]->name);
 }
 printf("\nReady Queue: ");
 for (int i = 0; i < os->ready_count; i++) {
 printf("%s ", os->ready_queue[i]->name);
 }
 printf("\nTotal Swap Time: %.3fs\n", os->total_swap_time);
}

/* Display process information */
void display_process(PCB *p) {
 const char *state_names[] = {"NEW", "READY", "RUNNING", "BLOCKED", "SWAPPED_OUT"};
 printf(" PID: %d, Name: %s, Size: %dMB, State: %s\n",
 p->pid, p->name, p->size_mb, state_names[p->state]);
}

/* Main function - Demonstration */
int main() {
 OS os;
 init_os(&os);

 /* Create processes */
 PCB processes[5];

 processes[0].pid = 1; strcpy(processes[0].name, "Process_A");
 processes[0].size_mb = 200; processes[0].state = NEW;

 processes[1].pid = 2; strcpy(processes[1].name, "Process_B");
 processes[1].size_mb = 150; processes[1].state = NEW;

 processes[2].pid = 3; strcpy(processes[2].name, "Process_C");
 processes[2].size_mb = 100; processes[2].state = NEW;

 processes[3].pid = 4; strcpy(processes[3].name, "Process_D");
 processes[3].size_mb = 80; processes[3].state = NEW;

 processes[4].pid = 5; strcpy(processes[4].name, "Process_E");
 processes[4].size_mb = 60; processes[4].state = NEW;

 printf("\n=== Loading Processes ===\n");

 /* Load first two processes */
 for (int i = 0; i < 2; i++) {
 if (allocate_memory(&os, &processes[i])) {
 os.ready_queue[os.ready_count++] = &processes[i];
 printf("Loaded: %s into memory\n", processes[i].name);
 }
 }

 display_memory_status(&os);

 /* Try to swap in another process */
 printf("\n=== Swapping Operations ===\n");
 swap_in(&os, &processes[2]);
 display_memory_status(&os);

 /* Swap out to demonstrate */
 printf("\n=== Swapping Out Process_A ===\n");
 swap_out(&os, &processes[0]);
 display_memory_status(&os);

 /* Swap it back in */
 printf("\n=== Swapping In Process_A ===\n");
 swap_in(&os, &processes[0]);
 display_memory_status(&os);

 /* Calculate performance */
 calculate_swap_time(100);

 return 0;
}
